export function getAerodromeRadios(code: string): AerodromeRadioRef[] {
  return AERODROME_RADIOS[code.trim().toUpperCase()] ?? [];
}

export function formatRadioLine(radio: AerodromeRadioRef): string {
  const service = radio.callsign ? `${radio.type} ${radio.callsign}` : radio.type;
  return `${service} ${radio.frequency}`;
}
